1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Empty / trivial cases ---
6	  it("empty quote → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Base premiums per item type (single-item quote, no modifiers, newcomer fresh customer adjustments excluded by using long-standing 2yr + follow-up — actually keep simple: use no modifiers via test inputs that neutralize all) ---
15	  // For isolation, the simplest approach: customer with 0 years, single item (first insurance applies). We will design test inputs so we can read off rules directly.
16	
17	  // Single item, no surcharges, fresh customer first contract: base + 10% first insurance + 5 fee
18	  it("quote single sword (steel, ench 3), newcomer first contract → 100 + 10 + 5 = 115 G", () => {
19	    const result = runScenario({
20	      customer: { yearsWithMHPCO: 0 },
21	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
22	    });
23	    expect(result).toEqual({ results: [{ premium: 115 }] });
24	  });
25	  it("quote single amulet (silver, ench 2), newcomer first contract → 60 + 6 + 5 = 71 G", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
29	    });
30	    expect(result).toEqual({ results: [{ premium: 71 }] });
31	  });
32	  it("quote single staff (wood, ench 1), newcomer first contract → 80 + 8 + 5 = 93 G", () => {
33	    const result = runScenario({
34	      customer: { yearsWithMHPCO: 0 },
35	      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 1, cursed: false }] }],
36	    });
37	    expect(result).toEqual({ results: [{ premium: 93 }] });
38	  });
39	  it("quote single potion (glass, ench 0), newcomer first contract → 40 + 4 + 5 = 49 G", () => {
40	    const result = runScenario({
41	      customer: { yearsWithMHPCO: 0 },
42	      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 0, cursed: false }] }],
43	    });
44	    expect(result).toEqual({ results: [{ premium: 49 }] });
45	  });
46	
47	  // --- Components and blocks ---
48	  it("quote 2 runes, newcomer first contract → base 50 G; +5 first ins + 5 fee = 60 G", () => {
49	    const result = runScenario({
50	      customer: { yearsWithMHPCO: 0 },
51	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
52	    });
53	    expect(result).toEqual({ results: [{ premium: 60 }] });
54	  });
55	  it("quote 3 runes (block applies) → base 60 G; +6 first ins + 5 fee = 71 G", () => {
56	    const result = runScenario({
57	      customer: { yearsWithMHPCO: 0 },
58	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] }],
59	    });
60	    expect(result).toEqual({ results: [{ premium: 71 }] });
61	  });
62	  it.todo("quote 4 runes (no block — block requires exactly 3) → base 100 G; +10 first ins + 5 fee = 115 G");
63	  it.todo("quote 7 runes → base 175 G (60 block + 4×25); +18 first ins (rounded up from 17.5) + 5 fee = 198 G");
64	
65	  // --- 'Alike' components clarification ---
66	  it.todo("quote 2 runes + 1 moonstone → base 75 G (no block: different types)");
67	  it.todo("quote 3 runes + 3 moonstones → base 120 G (two separate blocks of 60 each)");
68	
69	  // --- Item-specific modifiers ---
70	  it.todo("quote cursed sword (steel, ench 3), newcomer first → 100 + 50 curse + 10 first ins + 5 fee = 165 G");
71	  it.todo("quote sword with enchantment exactly 5 → high-enchantment surcharge applies (100 + 30 + 10 first ins + 5 fee = 145 G)");
72	  it.todo("quote sword with enchantment 4 → no high-enchantment surcharge (100 + 10 first ins + 5 fee = 115 G)");
73	  it.todo("quote cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 + 10 first ins + 5 fee = 195 G)");
74	
75	  // --- Policy-wide modifiers: loyalty threshold ---
76	  it.todo("customer with exactly 2 years → loyalty discount applies (sword steel ench 3: 100 + 10 first ins − 22 loyalty + 5 fee = 93 G)");
77	  it.todo("customer with 1 year → no loyalty discount (sword steel ench 3 → 115 G)");
78	
79	  // --- First-insurance surcharge always applies per item (clarifying ❓) ---
80	  it.todo("long-standing customer's brand-new sword still gets first-insurance surcharge per item");
81	
82	  // --- Follow-up contract discount ---
83	  it.todo("second quote in scenario → follow-up contract discount (15%) applies on policy total");
84	
85	  // --- Modifier scope: cursed surcharge applies only to cursed item, loyalty/follow-up apply to policy ---
86	  it.todo("cursed sword + plain amulet, newcomer first contract → policy base 160 + 50 curse + 16 first ins (10% of 160) + 5 fee = 231 G");
87	
88	  // --- Rounding in MHPCO's favor ---
89	  it.todo("premium calculation yielding 197.5 → rounded up to 198 G");
90	
91	  // --- Integration examples ---
92	  it.todo("newcomer (0y, no prev contract) with cursed sword (steel, ench 3) → premium 165 G");
93	  it.todo("3y customer's second quote of cursed sword (steel, ench 7) → premium 160 G");
94	
95	  // --- Unknown item type error ---
96	  it.todo("quote with unknown item type (broomstick) → throws (CLI must exit non-zero, stderr message)");
97	
98	  // --- Claims: basic standard reimbursement ---
99	  it.todo("standard reimbursement: regular sword (steel, ench 3) damage 500 → payout 400");
100	  it.todo("damage to a rune (insurance value 250), damage 200 → payout 100");
101	
102	  // --- Claims: enchantment >= 8 50% reimbursement ---
103	  it.todo("steel sword, enchantment 9, damage 1000 → payout 400 (50% then deductible)");
104	
105	  // --- Claims: dragon material full reimbursement ---
106	  it.todo("dragon-material sword, enchantment 5, damage 800 → payout 700 (full minus deductible)");
107	
108	  // --- Claims: dragon wins over high-enchantment ---
109	  it.todo("dragon-material sword, enchantment 9, damage 1000 → payout 400 (50% wins, then deductible)");
110	  it.todo("dragon-material sword, enchantment exactly 8, damage 1000 → payout 400 (high-enchant clause applies, then deductible)");
111	
112	  // --- Claims: deductible per damage event ---
113	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible applies per damaged item)");
114	
115	  // --- Claims: multiple items of same type ---
116	  it.todo("policy with 2 swords, dragon damages both — each entry treated as separate damage with own deductible");
117	  it.todo("claim with more sword damages than swords insured → CLI exits non-zero, whole claim rejected");
118	
119	  // --- Claims: cap exhaustion ---
120	  it.todo("policy sword + amulet: insurance sum 1600, cap 3200");
121	  it.todo("cursed sword (modified premium) → cap based on unmodified insurance value: cap 2000");
122	  it.todo("policy sword + 3 runes (block): insurance sum 1750 (block discount affects premium only)");
123	  it.todo("sword insured (cap 2000); two successive claims of 1500 each → 1st payout 1400 remainingCap 600; 2nd payout 600 remainingCap 0");
124	
125	  // --- Claims: payout rounding (down, MHPCO favor) ---
126	  it.todo("payout calculation yielding 350.5 → rounded down to 350");
127	
128	  // --- Claims: error cases ---
129	  it.todo("claim references damage entry whose item is not part of policy → exits non-zero, stderr");
130	  it.todo("claim references damage with unknown item type → exits non-zero, stderr");
131	  it.todo("claim with damage amount -200 → exits non-zero, stderr");
132	});
