1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export type QuoteItem = { type: string } & Record<string, unknown>;
6	
7	export interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	export interface ClaimStep {
13	  op: "claim";
14	  policy: number;
15	  incident: {
16	    cause: string;
17	    damages: Array<{ itemType: string; amount: number }>;
18	  };
19	}
20	
21	export type Step = QuoteStep | ClaimStep;
22	
23	export interface Scenario {
24	  customer: Customer;
25	  steps: Step[];
26	}
27	
28	export type StepResult =
29	  | { premium: number }
30	  | { payout: number; remainingCap: number };
31	
32	export interface ScenarioResult {
33	  results: StepResult[];
34	}
35	
36	const PROCESSING_FEE = 5;
37	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
38	
39	const BASE_PREMIUM: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	};
46	
47	const basePremiumFor = (item: QuoteItem): number =>
48	  BASE_PREMIUM[item.type] ?? 0;
49	
50	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
51	const BLOCK_BASE = 60;
52	
53	const baseForGroup = (type: string, count: number): number => {
54	  if (COMPONENT_TYPES.has(type) && count === 3) return BLOCK_BASE;
55	  return count * (BASE_PREMIUM[type] ?? 0);
56	};
57	
58	const quotePremium = (step: QuoteStep): StepResult => {
59	  const counts = new Map<string, number>();
60	  for (const item of step.items) {
61	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
62	  }
63	  let baseTotal = 0;
64	  for (const [type, count] of counts) {
65	    baseTotal += baseForGroup(type, count);
66	  }
67	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
68	  return { premium: baseTotal + firstInsuranceSurcharge + PROCESSING_FEE };
69	};
70	
71	const processStep = (step: Step): StepResult => {
72	  if (step.op === "quote") return quotePremium(step);
73	  return { payout: 0, remainingCap: 0 };
74	};
75	
76	export const runScenario = (scenario: Scenario): ScenarioResult => ({
77	  results: scenario.steps.map(processStep),
78	});
